#include <math.h>
#include <stdlib.h>
#include <stdio.h>
#include <omp.h>
#include "./main.h"

void kernel_gpu_openmp(params_common d_common,
                       fp* d_frame,
                       int d_frame_no,
                       int* d_endoRow,
                       int* d_endoCol,
                       int* d_tEndoRowLoc,
                       int* d_tEndoColLoc,
                       int* d_epiRow,
                       int* d_epiCol,
                       int* d_tEpiRowLoc,
                       int* d_tEpiColLoc,
                       fp* d_endoT,
                       fp* d_epiT,
                       fp* d_in2_all,
                       fp* d_conv_all,
                       fp* d_in2_pad_cumv_all,
                       fp* d_in2_pad_cumv_sel_all,
                       fp* d_in2_sub_cumh_all,
                       fp* d_in2_sub_cumh_sel_all,
                       fp* d_in2_sub2_all,
                       fp* d_in2_sqr_all,
                       fp* d_in2_sqr_sub2_all,
                       fp* d_in_sqr_all,
                       fp* d_tMask_all,
                       fp* d_mask_conv_all,
                       fp* d_in_mod_temp_all,
                       fp* in_partial_sum_all,
                       fp* in_sqr_partial_sum_all,
                       fp* par_max_val_all,
                       int* par_max_coo_all,
                       fp* in_final_sum_all,
                       fp* in_sqr_final_sum_all,
                       fp* denomT_all,
                       fp* checksum)
{
    int total_threads = d_common.allPoints * NUMBER_THREADS;

#pragma omp parallel
    {
        int i, j, row, col, ori_row, ori_col, pointer, ori_pointer, loc_pointer;
        int rot_row, rot_col, in2_rowlow, in2_collow;
        int ic, jc, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
        fp s, sum, temp, temp2;
        int position, pos_ori, location, cent;
        int tMask_row, tMask_col;
        fp largest_value_current = 0;
        fp largest_value = 0;
        int largest_coordinate_current = 0;
        int largest_coordinate = 0;
        fp fin_max_val = 0;
        int fin_max_coo = 0;
        int largest_row, largest_col, offset_row, offset_col;
        fp mean, mean_sqr, variance, deviation;
        int ei_new;

        int thread_id = omp_get_thread_num();

        int bx = thread_id / NUMBER_THREADS;
        int tx = thread_id % NUMBER_THREADS;

        if (bx < d_common.allPoints) {

            int d_unique_point_no;
            int* d_unique_d_Row;
            int* d_unique_d_Col;
            int* d_unique_d_tRowLoc;
            int* d_unique_d_tColLoc;
            fp* d_in;

            if (d_common.endoPoints > bx) {
                d_unique_point_no = bx;
                d_unique_d_Row = d_endoRow;
                d_unique_d_Col = d_endoCol;
                d_unique_d_tRowLoc = d_tEndoRowLoc;
                d_unique_d_tColLoc = d_tEndoColLoc;
                d_in = &d_endoT[d_unique_point_no * d_common.in_elem];
            } else {
                d_unique_point_no = bx - d_common.endoPoints;
                d_unique_d_Row = d_epiRow;
                d_unique_d_Col = d_epiCol;
                d_unique_d_tRowLoc = d_tEpiRowLoc;
                d_unique_d_tColLoc = d_tEpiColLoc;
                d_in = &d_epiT[d_unique_point_no * d_common.in_elem];
            }

            fp* d_unique_d_in2 = &d_in2_all[bx * d_common.in2_elem];
            fp* d_unique_d_conv = &d_conv_all[bx * d_common.conv_elem];
            fp* d_unique_d_in2_pad_cumv = &d_in2_pad_cumv_all[bx * d_common.in2_pad_cumv_elem];
            fp* d_unique_d_in2_pad_cumv_sel = &d_in2_pad_cumv_sel_all[bx * d_common.in2_pad_cumv_sel_elem];
            fp* d_unique_d_in2_sub_cumh = &d_in2_sub_cumh_all[bx * d_common.in2_sub_cumh_elem];
            fp* d_unique_d_in2_sub_cumh_sel = &d_in2_sub_cumh_sel_all[bx * d_common.in2_sub_cumh_sel_elem];
            fp* d_unique_d_in2_sub2 = &d_in2_sub2_all[bx * d_common.in2_sub2_elem];
            fp* d_unique_d_in2_sqr = &d_in2_sqr_all[bx * d_common.in2_sqr_elem];
            fp* d_unique_d_in2_sqr_sub2 = &d_in2_sqr_sub2_all[bx * d_common.in2_sqr_sub2_elem];
            fp* d_unique_d_in_sqr = &d_in_sqr_all[bx * d_common.in_sqr_elem];
            fp* d_unique_d_tMask = &d_tMask_all[bx * d_common.tMask_elem];
            fp* d_unique_d_mask_conv = &d_mask_conv_all[bx * d_common.mask_conv_elem];

            fp* d_in_mod_temp = &d_in_mod_temp_all[bx * d_common.in_elem];
            fp* in_partial_sum = &in_partial_sum_all[bx * d_common.in_cols];
            fp* in_sqr_partial_sum = &in_sqr_partial_sum_all[bx * d_common.in_sqr_rows];
            fp* par_max_val = &par_max_val_all[bx * d_common.mask_conv_rows];
            int* par_max_coo = &par_max_coo_all[bx * d_common.mask_conv_rows];

            fp* in_final_sum = &in_final_sum_all[bx];
            fp* in_sqr_final_sum = &in_sqr_final_sum_all[bx];
            fp* denomT = &denomT_all[bx];

#pragma omp barrier

#ifdef TEST_CHECKSUM
            if (bx == 0 && tx == 0) {
                for (i = 0; i < CHECK; i++) {
                    checksum[i] = 0;
                }
            }
#endif

#pragma omp barrier

            if (d_frame_no == 0) {
#ifdef INIT
                if (tx == 0) {
                    for (i = 0; i < d_common.no_frames; i++) {
                        d_unique_d_tRowLoc[d_unique_point_no * d_common.no_frames + i] = 0;
                        d_unique_d_tColLoc[d_unique_point_no * d_common.no_frames + i] = 0;
                    }
                    for (i = 0; i < d_common.in_elem; i++) {
                        d_in[i] = 0;
                    }
                }
#endif
#pragma omp barrier

                if (tx == 0) {
                    pointer = d_unique_point_no * d_common.no_frames + d_frame_no;
                    d_unique_d_tRowLoc[pointer] = d_unique_d_Row[d_unique_point_no];
                    d_unique_d_tColLoc[pointer] = d_unique_d_Col[d_unique_point_no];
                }

#pragma omp barrier

                for (int idx = tx; idx < d_common.in_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in_rows - 1;
                    col = (idx + 1) / d_common.in_rows;
                    if ((idx + 1) % d_common.in_rows == 0) {
                        row = d_common.in_rows - 1;
                        col -= 1;
                    }
                    ori_row = d_unique_d_Row[d_unique_point_no] - 25 + row - 1;
                    ori_col = d_unique_d_Col[d_unique_point_no] - 25 + col - 1;
                    ori_pointer = ori_col * d_common.frame_rows + ori_row;
                    d_in[col * d_common.in_rows + row] = d_frame[ori_pointer];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in_elem; i++) {
                        checksum[0] += d_in[i];
                    }
                }
#pragma omp barrier
#endif
            }

            if (d_frame_no != 0) {
#ifdef INIT
                if (tx == 0) {
                    for (i = 0; i < d_common.in2_elem; i++) d_unique_d_in2[i] = 0;
                    for (i = 0; i < d_common.conv_elem; i++) d_unique_d_conv[i] = 0;
                    for (i = 0; i < d_common.in2_pad_cumv_elem; i++) d_unique_d_in2_pad_cumv[i] = 0;
                    for (i = 0; i < d_common.in2_pad_cumv_sel_elem; i++) d_unique_d_in2_pad_cumv_sel[i] = 0;
                    for (i = 0; i < d_common.in2_sub_cumh_elem; i++) d_unique_d_in2_sub_cumh[i] = 0;
                    for (i = 0; i < d_common.in2_sub_cumh_sel_elem; i++) d_unique_d_in2_sub_cumh_sel[i] = 0;
                    for (i = 0; i < d_common.in2_sub2_elem; i++) d_unique_d_in2_sub2[i] = 0;
                    for (i = 0; i < d_common.in2_sqr_elem; i++) d_unique_d_in2_sqr[i] = 0;
                    for (i = 0; i < d_common.in2_sqr_sub2_elem; i++) d_unique_d_in2_sqr_sub2[i] = 0;
                    for (i = 0; i < d_common.in_sqr_elem; i++) d_unique_d_in_sqr[i] = 0;
                    for (i = 0; i < d_common.tMask_elem; i++) d_unique_d_tMask[i] = 0;
                    for (i = 0; i < d_common.mask_conv_elem; i++) d_unique_d_mask_conv[i] = 0;
                    for (i = 0; i < d_common.in_elem; i++) d_in_mod_temp[i] = 0;
                    for (i = 0; i < d_common.in_cols; i++) in_partial_sum[i] = 0;
                    for (i = 0; i < d_common.in_sqr_rows; i++) in_sqr_partial_sum[i] = 0;
                    for (i = 0; i < d_common.mask_conv_rows; i++) par_max_val[i] = 0;
                    for (i = 0; i < d_common.mask_conv_rows; i++) par_max_coo[i] = 0;
                    in_final_sum[0] = 0;
                    in_sqr_final_sum[0] = 0;
                    denomT[0] = 0;
                }
#endif
#pragma omp barrier

                in2_rowlow = d_unique_d_Row[d_unique_point_no] - d_common.sSize;
                in2_collow = d_unique_d_Col[d_unique_point_no] - d_common.sSize;

                for (int idx = tx; idx < d_common.in2_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in2_rows - 1;
                    col = (idx + 1) / d_common.in2_rows;
                    if ((idx + 1) % d_common.in2_rows == 0) {
                        row = d_common.in2_rows - 1;
                        col -= 1;
                    }
                    ori_row = row + in2_rowlow - 1;
                    ori_col = col + in2_collow - 1;
                    d_unique_d_in2[idx] = d_frame[ori_col * d_common.frame_rows + ori_row];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_elem; i++) {
                        checksum[1] += d_unique_d_in2[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in_rows - 1;
                    col = (idx + 1) / d_common.in_rows;
                    if ((idx + 1) % d_common.in_rows == 0) {
                        row = d_common.in_rows - 1;
                        col -= 1;
                    }
                    rot_row = (d_common.in_rows - 1) - row;
                    rot_col = (d_common.in_rows - 1) - col;
                    d_in_mod_temp[idx] = d_in[rot_col * d_common.in_rows + rot_row];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in_elem; i++) {
                        checksum[2] += d_in_mod_temp[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.conv_elem; idx += NUMBER_THREADS) {
                    ic = (idx + 1) % d_common.conv_rows;
                    jc = (idx + 1) / d_common.conv_rows;
                    if ((idx + 1) % d_common.conv_rows == 0) {
                        ic = d_common.conv_rows;
                        jc -= 1;
                    }
                    j = jc + d_common.joffset;
                    jp1 = j + 1;
                    if (jp1 > d_common.in2_cols) {
                        ja1 = jp1 - d_common.in2_cols;
                    } else {
                        ja1 = 1;
                    }
                    if (d_common.in_cols < j) {
                        ja2 = d_common.in_cols;
                    } else {
                        ja2 = j;
                    }
                    i = ic + d_common.ioffset;
                    ip1 = i + 1;
                    if (d_common.in2_rows < ip1) {
                        ia1 = ip1 - d_common.in2_rows;
                    } else {
                        ia1 = 1;
                    }
                    if (i > d_common.in_rows) {
                        ia2 = d_common.in_rows;
                    } else {
                        ia2 = i;
                    }
                    s = 0;
                    for (ja = ja1; ja <= ja2; ja++) {
                        jb = jp1 - ja;
                        for (ia = ia1; ia <= ia2; ia++) {
                            ib = ip1 - ia;
                            s += d_in_mod_temp[d_common.in_rows * (ja - 1) + ia - 1] * d_unique_d_in2[d_common.in2_rows * (jb - 1) + ib - 1];
                        }
                    }
                    d_unique_d_conv[idx] = s;
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.conv_elem; i++) {
                        checksum[3] += d_unique_d_conv[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_pad_cumv_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in2_pad_cumv_rows - 1;
                    col = (idx + 1) / d_common.in2_pad_cumv_rows;
                    if ((idx + 1) % d_common.in2_pad_cumv_rows == 0) {
                        row = d_common.in2_pad_cumv_rows - 1;
                        col -= 1;
                    }
                    if (row > (d_common.in2_pad_add_rows - 1) &&
                        (d_common.in2_pad_add_rows + d_common.in2_rows) > row &&
                        (d_common.in2_pad_add_cols - 1) < col &&
                        (d_common.in2_pad_add_cols + d_common.in2_cols) > col) {
                        ori_row = row - d_common.in2_pad_add_rows;
                        ori_col = col - d_common.in2_pad_add_cols;
                        d_unique_d_in2_pad_cumv[idx] = d_unique_d_in2[ori_col * d_common.in2_rows + ori_row];
                    } else {
                        d_unique_d_in2_pad_cumv[idx] = 0;
                    }
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_pad_cumv_elem; i++) {
                        checksum[4] += d_unique_d_in2_pad_cumv[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_pad_cumv_cols; idx += NUMBER_THREADS) {
                    pos_ori = idx * d_common.in2_pad_cumv_rows;
                    sum = 0;
                    for (position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position++) {
                        d_unique_d_in2_pad_cumv[position] += sum;
                        sum = d_unique_d_in2_pad_cumv[position];
                    }
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_pad_cumv_cols; i++) {
                        checksum[5] += d_unique_d_in2_pad_cumv[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_pad_cumv_sel_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in2_pad_cumv_sel_rows - 1;
                    col = (idx + 1) / d_common.in2_pad_cumv_sel_rows;
                    if ((idx + 1) % d_common.in2_pad_cumv_sel_rows == 0) {
                        row = d_common.in2_pad_cumv_sel_rows - 1;
                        col -= 1;
                    }
                    ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
                    ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
                    d_unique_d_in2_pad_cumv_sel[idx] = d_unique_d_in2_pad_cumv[ori_col * d_common.in2_pad_cumv_rows + ori_row];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_pad_cumv_sel_elem; i++) {
                        checksum[6] += d_unique_d_in2_pad_cumv_sel[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub_cumh_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in2_sub_cumh_rows - 1;
                    col = (idx + 1) / d_common.in2_sub_cumh_rows;
                    if ((idx + 1) % d_common.in2_sub_cumh_rows == 0) {
                        row = d_common.in2_sub_cumh_rows - 1;
                        col -= 1;
                    }
                    ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
                    ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
                    d_unique_d_in2_sub_cumh[idx] = d_unique_d_in2_pad_cumv[ori_col * d_common.in2_pad_cumv_rows + ori_row];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub_cumh_elem; i++) {
                        checksum[7] += d_unique_d_in2_sub_cumh[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub_cumh_elem; idx += NUMBER_THREADS) {
                    d_unique_d_in2_sub_cumh[idx] = d_unique_d_in2_pad_cumv_sel[idx] - d_unique_d_in2_sub_cumh[idx];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub_cumh_elem; i++) {
                        checksum[8] += d_unique_d_in2_sub_cumh[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub_cumh_rows; idx += NUMBER_THREADS) {
                    pos_ori = idx;
                    sum = 0;
                    for (position = pos_ori; position < pos_ori + d_common.in2_sub_cumh_elem; position += d_common.in2_sub_cumh_rows) {
                        d_unique_d_in2_sub_cumh[position] += sum;
                        sum = d_unique_d_in2_sub_cumh[position];
                    }
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub_cumh_rows; i++) {
                        checksum[9] += d_unique_d_in2_sub_cumh[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub_cumh_sel_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in2_sub_cumh_sel_rows - 1;
                    col = (idx + 1) / d_common.in2_sub_cumh_sel_rows;
                    if ((idx + 1) % d_common.in2_sub_cumh_sel_rows == 0) {
                        row = d_common.in2_sub_cumh_sel_rows - 1;
                        col -= 1;
                    }
                    ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
                    ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
                    d_unique_d_in2_sub_cumh_sel[idx] = d_unique_d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub_cumh_sel_elem; i++) {
                        checksum[10] += d_unique_d_in2_sub_cumh_sel[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub2_elem; idx += NUMBER_THREADS) {
                    row = (idx + 1) % d_common.in2_sub2_rows - 1;
                    col = (idx + 1) / d_common.in2_sub2_rows;
                    if ((idx + 1) % d_common.in2_sub2_rows == 0) {
                        row = d_common.in2_sub2_rows - 1;
                        col -= 1;
                    }
                    ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
                    ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
                    d_unique_d_in2_sqr_sub2[idx] = d_unique_d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub2_elem; i++) {
                        checksum[21] += d_unique_d_in2_sqr_sub2[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub2_elem; idx += NUMBER_THREADS) {
                    d_unique_d_in2_sqr_sub2[idx] = d_unique_d_in2_sub_cumh_sel[idx] - d_unique_d_in2_sqr_sub2[idx];
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub2_elem; i++) {
                        checksum[22] += d_unique_d_in2_sqr_sub2[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in2_sub2_elem; idx += NUMBER_THREADS) {
                    temp = d_unique_d_in2_sub2[idx];
                    temp2 = d_unique_d_in2_sqr_sub2[idx] - (temp * temp / d_common.in_elem);
                    if (temp2 < 0) {
                        temp2 = 0;
                    }
                    d_unique_d_in2_sqr_sub2[idx] = sqrt(temp2);
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in2_sub2_elem; i++) {
                        checksum[23] += d_unique_d_in2_sqr_sub2[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in_sqr_elem; idx += NUMBER_THREADS) {
                    temp = d_in[idx];
                    d_unique_d_in_sqr[idx] = temp * temp;
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in_sqr_elem; i++) {
                        checksum[24] += d_unique_d_in_sqr[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in_cols; idx += NUMBER_THREADS) {
                    sum = 0;
                    for (i = 0; i < d_common.in_rows; i++) {
                        sum += d_in[idx * d_common.in_rows + i];
                    }
                    in_partial_sum[idx] = sum;
                }

#pragma omp barrier

#ifdef TEST_CHECKSUM
                if (bx == 0 && tx == 0) {
                    for (i = 0; i < d_common.in_cols; i++) {
                        checksum[25] += in_partial_sum[i];
                    }
                }
#pragma omp barrier
#endif

                for (int idx = tx; idx < d_common.in_sqr_rows; idx += NUMBER_THREADS) {
                    sum = 0;
                    for (i = 0; i < d_common.in_sqr_cols; i++) {
